package main

import (
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// minimalPDF returns the bytes of a valid minimal PDF with the given number of
// blank pages. Byte offsets in the xref table are computed at build time so
// pdfcpu's strict parser accepts the result.
func minimalPDF(pageCount int) []byte {
	var buf bytes.Buffer
	offsets := make([]int, 2+pageCount) // one entry per object (1-indexed)

	w := func(s string) { buf.WriteString(s) }
	wf := func(format string, args ...any) { fmt.Fprintf(&buf, format, args...) }
	startObj := func(n int) {
		offsets[n-1] = buf.Len()
		wf("%d 0 obj\n", n)
	}
	endObj := func() { w("endobj\n") }

	w("%PDF-1.4\n")

	startObj(1)
	w("<< /Type /Catalog /Pages 2 0 R >>\n")
	endObj()

	var kids strings.Builder
	for i := range pageCount {
		if i > 0 {
			kids.WriteByte(' ')
		}
		fmt.Fprintf(&kids, "%d 0 R", 3+i)
	}
	startObj(2)
	wf("<< /Type /Pages /Kids [%s] /Count %d >>\n", kids.String(), pageCount)
	endObj()

	for i := range pageCount {
		startObj(3 + i)
		w("<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] >>\n")
		endObj()
	}

	xrefOff := buf.Len()
	totalObjs := 2 + pageCount + 1 // objects 0..2+pageCount
	wf("xref\n0 %d\n", totalObjs)
	wf("0000000000 65535 f\r\n") // free entry for object 0
	for _, off := range offsets {
		wf("%010d 00000 n\r\n", off)
	}
	wf("trailer\n<< /Size %d /Root 1 0 R >>\n", totalObjs)
	wf("startxref\n%d\n", xrefOff)
	w("%%EOF\n")

	return buf.Bytes()
}

func writePDF(t *testing.T, path string, pages int) {
	t.Helper()
	if err := os.WriteFile(path, minimalPDF(pages), 0o644); err != nil {
		t.Fatal(err)
	}
}

func TestMergePDFs(t *testing.T) {
	tmp := t.TempDir()
	front := filepath.Join(tmp, "front.pdf")
	back := filepath.Join(tmp, "back.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, front, 3)
	writePDF(t, back, 3)

	if err := mergePDFs(front, back, out, false); err != nil {
		t.Fatal(err)
	}

	count, err := pdfPageCount(out)
	if err != nil {
		t.Fatal(err)
	}
	if count != 6 {
		t.Errorf("got %d pages, want 6", count)
	}
}

func TestMergePDFsReverseBack(t *testing.T) {
	tmp := t.TempDir()
	front := filepath.Join(tmp, "front.pdf")
	back := filepath.Join(tmp, "back.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, front, 3)
	writePDF(t, back, 3)

	if err := mergePDFs(front, back, out, true); err != nil {
		t.Fatal(err)
	}

	count, err := pdfPageCount(out)
	if err != nil {
		t.Fatal(err)
	}
	if count != 6 {
		t.Errorf("got %d pages, want 6", count)
	}
}

func TestMergePDFsUnequalCounts(t *testing.T) {
	tmp := t.TempDir()
	front := filepath.Join(tmp, "front.pdf")
	back := filepath.Join(tmp, "back.pdf")
	out := filepath.Join(tmp, "merged.pdf")

	writePDF(t, front, 4)
	writePDF(t, back, 3)

	if err := mergePDFs(front, back, out, false); err != nil {
		t.Fatal(err)
	}

	// 3 interleaved pairs (6 pages) + 1 extra front page = 7
	count, err := pdfPageCount(out)
	if err != nil {
		t.Fatal(err)
	}
	if count != 7 {
		t.Errorf("got %d pages, want 7", count)
	}
}

func TestSplitPDF(t *testing.T) {
	tmp := t.TempDir()
	in := filepath.Join(tmp, "input.pdf")
	outDir := filepath.Join(tmp, "out")
	if err := os.MkdirAll(outDir, 0o755); err != nil {
		t.Fatal(err)
	}

	writePDF(t, in, 6)

	// Split after pages 2 and 4 → three files: 1-2, 3-4, 5-6
	parts, err := splitPDF(in, []int{2, 4}, outDir)
	if err != nil {
		t.Fatal(err)
	}

	if len(parts) != 3 {
		t.Fatalf("got %d parts, want 3", len(parts))
	}

	for i, want := range []int{2, 2, 2} {
		got, err := pdfPageCount(parts[i])
		if err != nil {
			t.Fatalf("part %d: %v", i, err)
		}
		if got != want {
			t.Errorf("part %d: got %d pages, want %d", i, got, want)
		}
	}
}

func TestSplitPDFSinglePage(t *testing.T) {
	tmp := t.TempDir()
	in := filepath.Join(tmp, "input.pdf")
	outDir := filepath.Join(tmp, "out")
	if err := os.MkdirAll(outDir, 0o755); err != nil {
		t.Fatal(err)
	}

	writePDF(t, in, 4)

	// No split points → single output file with all pages
	parts, err := splitPDF(in, nil, outDir)
	if err != nil {
		t.Fatal(err)
	}

	if len(parts) != 1 {
		t.Fatalf("got %d parts, want 1", len(parts))
	}

	got, err := pdfPageCount(parts[0])
	if err != nil {
		t.Fatal(err)
	}
	if got != 4 {
		t.Errorf("got %d pages, want 4", got)
	}
}

